const fs = require('fs').promises;

async function readLogFile(filename) {
  try {
    const data = await fs.readFile(filename, 'utf8');
    return data;
  } catch (error) {
    throw new Error(`Error reading file ${filename}: ${error.message}`);
  }
}

module.exports = readLogFile;